INSERT INTO motorcycles (id, name, article_number, brand, vin, year, engine_cc, color, mc_type, warehouse, stock, reorder_qty, cost, selling_price, vendor, description) VALUES
('MC-001','CBR 600RR','HON-CBR600RR-2024','Honda','JH2PC40098M200001',2024,599,'Repsol Red / White','New','Warehouse A',3,2,92000,124900,'Honda Motor Distributors Sdn Bhd','The Honda CBR600RR is a high-performance supersport motorcycle featuring a 599cc inline-4 engine with Ram Air Direct intake. Lightweight aluminum twin-spar frame, fully adjustable suspension, and aggressive aerodynamics make it a track-ready machine.'),
('MC-002','CB650R','HON-CB650R-2024','Honda','JH2PC41023M201102',2024,649,'Graphite Black','New','Warehouse A',2,2,78000,104900,'Honda Motor Distributors Sdn Bhd','The Honda CB650R is a neo-retro naked roadster with a smooth 649cc inline-4 engine. Featuring a round LED headlight, compact chassis, and Showa SFF-BP forks. Perfect blend of classic styling and modern performance for everyday spirited riding.'),
('MC-003','MT-07','YAM-MT07-2024','Yamaha','JYARM24E4KA000234',2024,689,'Midnight Black','New','Warehouse B',5,2,72000,94900,'Yamaha Motor Malaysia Sdn Bhd','The Yamaha MT-07 is a naked street fighter powered by a 689cc CP2 parallel-twin engine. Known for its torquey mid-range power delivery, lightweight chassis, and aggressive styling. Ideal for both city commuting and weekend rides.'),
('MC-004','Ninja 400','KAW-NIN400-2024','Kawasaki','JKBZXJA12LBA00512',2024,399,'Lime Green / Ebony','New','Warehouse B',4,2,54000,72900,'Kawasaki Motors (M) Sdn Bhd','The Kawasaki Ninja 400 is an entry-level supersport with a 399cc parallel-twin engine. Lightweight trellis frame, Assist and Slipper clutch, and full fairing bodywork. Perfect for beginner to intermediate riders looking for sporty performance.'),
('MC-005','Z900','KAW-Z900-2024','Kawasaki','JKAZR4A15PA003381',2024,948,'Metallic Spark Black','New','Warehouse B',2,2,86000,114900,'Kawasaki Motors (M) Sdn Bhd','The Kawasaki Z900 is a high-performance naked bike built around a 948cc inline-4 engine with 125hp. Trellis frame, four-way adjustable front forks, and advanced electronics including Kawasaki Traction Control and four riding modes.'),
('MC-006','Versys 650','KAW-VER650-2023','Kawasaki','JKALE650XPA006712',2023,649,'Candy Lime Green','Trade-In','Warehouse B',3,2,67000,88900,'Kawasaki Motors (M) Sdn Bhd','The Kawasaki Versys 650 is a versatile all-rounder with a 649cc parallel-twin engine. Comfortable upright riding position, adjustable windscreen, and long-travel suspension make it a strong choice for commuting, touring, and occasional off-road use.'),
('MC-007','GSX-R750','SUZ-GSXR750-2023','Suzuki','JS1GR7LA5P2100789',2023,750,'Metallic Triton Blue','New','Warehouse C',2,1,98000,132900,'Suzuki Malaysia Sdn Bhd','The Suzuki GSX-R750 is the legendary supersport that defined the class. A 750cc inline-4 engine with advanced fuel injection, a compact twin-spar aluminum frame, and race-derived suspension components for supreme handling.'),
('MC-008','V-Strom 650 XT','SUZ-VST650XT-2024','Suzuki','JS1VP51B5P2200345',2024,645,'Champion Yellow','New','Warehouse C',3,2,75000,99900,'Suzuki Malaysia Sdn Bhd','The Suzuki V-Strom 650 XT is a mid-size adventure tourer. Features a 645cc V-twin engine, wire-spoke wheels, knuckle guards, and Suzuki Traction Control System. Built for long-haul adventure with excellent fuel economy.'),
('MC-009','Hayabusa','SUZ-HAYA-2024','Suzuki','JS1GX72B3P2300102',2024,1340,'Pearl Brilliant White / Candy Burnt Gold','New','Warehouse C',1,1,165000,219900,'Suzuki Malaysia Sdn Bhd','The Suzuki Hayabusa is the iconic ultimate sport bike with a 1340cc inline-4 engine producing 187hp. Features Launch Control Mode, Cornering ABS, and Active Speed Limiter. A legend reborn.'),
('MC-010','R 1250 GS','BMW-R1250GS-2024','BMW Motorrad','WB10A0204N6D00321',2024,1254,'Style GS Triple Black','New','Warehouse D',2,1,158000,209900,'BMW Motorrad Malaysia','The BMW R 1250 GS is the benchmark adventure touring motorcycle. Powered by a 1254cc ShiftCam boxer twin engine with 136hp, intelligent electronics including dynamic traction control, hill start control, and multiple riding modes for all terrain.'),
('MC-011','Monster 797','DUC-MON797-2023','Ducati','ZDMABBBW0KB000456',2023,803,'Ducati Red','Trade-In','Warehouse D',1,1,105000,139900,'Ducati Asia Pacific Pte Ltd','The Ducati Monster 797 is an iconic naked roadster with a Desmodue L-twin 803cc engine producing 73hp. Its steel trellis frame, single-sided swingarm, and minimalist design embody the essence of the Monster lineage.'),
('MC-012','Street Triple RS','TRI-STRRS-2024','Triumph','SMTC12HX4LJ000678',2024,765,'Sapphire Black','New','Warehouse D',3,2,116000,154900,'Triumph Motorcycles (Asia) Ltd','The Triumph Street Triple RS is the pinnacle of the Street Triple range. A 765cc triple-cylinder engine produces 123hp. Fully adjustable suspension, Brembo brakes, and a full suite of rider aids complete the package.'),
('MC-013','Scout Bobber','IND-SCBOB-2024','Indian','56KMTA008P3001024',2024,1133,'Stealth Gray','Commission','Warehouse A',2,1,139000,184900,'Indian Motorcycle APAC Pte Ltd','The Indian Scout Bobber is a stripped-down cruiser built on the 1133cc Thunder Stroke V-twin. Mid-mounted foot controls, blacked-out styling, and a low seat height make it as approachable as it is striking on the street.'),
('MC-014','Chief Dark Horse','IND-CHDH-2024','Indian','56KMTB003P3001567',2024,1890,'Black Smoke','New','Warehouse A',1,1,199000,264900,'Indian Motorcycle APAC Pte Ltd','The Indian Chief Dark Horse is a blacked-out powerhouse built around the 1890cc Thunder Stroke 116 V-twin producing 126ft-lb of torque. Bold, aggressive, and steeped in American motorcycle heritage.'),
('MC-015','FTR 1200 S','IND-FTR1200S-2023','Indian','56KMTC007P3002001',2023,1203,'Race Replica Red / White','Trade-In','Warehouse A',1,2,146000,194900,'Indian Motorcycle APAC Pte Ltd','The Indian FTR 1200 S is a flat-track-inspired street fighter with a 1203cc V-twin engine. Full-colour TFT touchscreen, Brembo brakes, fully adjustable suspension, and switchable ABS.'),
('MC-016','Meteor 350','RE-MET350-2024','Royal Enfield','ME3FH3511P2900456',2024,349,'Fireball Orange','New','Warehouse B',6,3,41000,54900,'Royal Enfield Motors (M) Sdn Bhd','The Royal Enfield Meteor 350 is a relaxed leisure cruiser powered by a 349cc single-cylinder SOHC engine. Star gazer navigation pod, Tripper turn-by-turn navigation, and dual-channel ABS.'),
('MC-017','Himalayan 450','RE-HIM450-2024','Royal Enfield','ME3FH4512P2901122',2024,452,'Slate Himalayan Salt','New','Warehouse C',2,2,56000,74900,'Royal Enfield Motors (M) Sdn Bhd','The Royal Enfield Himalayan 450 is a purpose-built adventure motorcycle with a liquid-cooled 452cc Sherpa engine producing 40hp. Tripper navigation, long-travel suspension, wire-spoke wheels, and 17L fuel tank.'),
('MC-018','Classic 350','RE-CLS350-BLK-2024','Royal Enfield','ME3FH3510P2902789',2024,349,'Halcyon Black','Trade-In','Warehouse C',1,3,45000,59900,'Royal Enfield Motors (M) Sdn Bhd','The Royal Enfield Classic 350 is the best-selling retro motorcycle in the world. A 349cc J-platform engine delivers effortless torque. Dual-channel ABS, chrome details, and timeless styling. Currently low on stock.'),
('MC-019','Interceptor 650','RE-INT650-2024','Royal Enfield','ME3FH6501P2903456',2024,648,'Ventura Blue','New','Warehouse C',4,2,60000,79900,'Royal Enfield Motors (M) Sdn Bhd','The Royal Enfield Interceptor 650 is a modern classic parallel-twin with a 648cc air-oil cooled engine producing 47hp. Praised worldwide as one of the best-value motorcycles available.'),
('MC-020','Cruiser 400','VOG-CRU400-2024','Vogue','VGM4CR400P1000088',2024,400,'Pearl Ivory / Chrome','New','Warehouse D',3,2,49000,64900,'Vogue Motorcycle Industries','The Vogue Cruiser 400 is a boutique-styled low-slung cruiser with a 400cc single-cylinder engine. Custom chrome detailing, springer front fork, and a retro teardrop tank create a head-turning street presence.'),
('MC-021','Urban 250','VOG-URB250-2024','Vogue','VGM2UR250P1000312',2024,249,'Gloss Matte Black','New','Warehouse D',5,3,32000,42900,'Vogue Motorcycle Industries','The Vogue Urban 250 is a stylish lightweight commuter for city streets. A 249cc single-cylinder fuel-injected engine, USD front forks, and a minimalist instrument panel. Ideal for A2 licence holders.'),
('MC-022','Retro Classic 500','VOG-RTC500-2023','Vogue','VGM5RC500P1000045',2023,499,'British Racing Green','Commission','Warehouse D',1,2,64000,84900,'Vogue Motorcycle Industries','The Vogue Retro Classic 500 is a hand-finished neo-retro roadster with a 499cc parallel-twin engine. Hand-stitched leather seat, brushed stainless exhaust, and classic spoked wheels. Limited production runs ensure exclusivity.');
INSERT INTO spare_parts (id, name, article_number, brand, category, stock, reorder_qty, cost, selling_price, vendor, description) VALUES
('SP-001','Oil Filter','ENG-OILF-HON-001','Honda Genuine Parts','Engine',25,10,8,18,'Honda Motor Distributors Sdn Bhd','Genuine Honda oil filter for 4-stroke engines. Removes contaminants and metal particles from engine oil to maintain optimal lubrication and extend engine life.'),
('SP-002','Iridium Spark Plug (Set of 4)','IGN-PLUG-NGK-IR4','NGK','Engine',30,15,12,28,'NGK Spark Plugs (Malaysia) Sdn Bhd','NGK Iridium IX spark plugs for maximum ignitability and superior anti-fouling. Ultra-fine 0.6mm iridium tip ensures longer service life and improved throttle response.'),
('SP-003','Air Filter','ENG-AIRF-KN-001','K&N Engineering','Engine',20,8,35,75,'K&N Engineering Inc.','K&N high-flow air filter with washable and reusable cotton gauze media. Increases airflow up to 50% compared to stock paper filters for improved horsepower and throttle response.'),
('SP-004','Engine Coolant 1L (Blue)','ENG-COOL-MOTUL-1L','Motul','Engine',35,15,10,22,'Motul Asia Pacific Pte Ltd','Motul Motocool Expert ready-to-use engine coolant with corrosion inhibitors. Protects aluminium alloy engines down to -25 degrees C. ASTM D3306 compliant. Renew every 2 years or 30,000km.'),
('SP-005','Piston Ring Set','ENG-PIST-RE350-001','Royal Enfield Genuine','Engine',3,5,38,85,'Royal Enfield Motors (M) Sdn Bhd','Genuine Royal Enfield piston ring set for J-platform 349cc engines. Includes compression rings and oil control ring. Restores compression and returns engine to factory specification.'),
('SP-006','Front Brake Pad Set','BRK-PAD-F-EBC-001','EBC Brakes','Brakes',18,8,22,48,'EBC Brakes Distribution Asia','EBC FA series sintered front brake pads. High-performance sintered compound provides consistent braking in all weather conditions. Direct OEM replacement with improved bite and fade resistance.'),
('SP-007','Rear Brake Disc Rotor','BRK-DSC-R-BRB-001','Brembo','Brakes',8,4,55,120,'Brembo S.p.A. Asia Pacific','Brembo T-Drive floating rear brake disc. Precision-machined stainless steel with a floating mount design to reduce heat transfer. Provides better thermal performance and consistent braking feel.'),
('SP-008','Brake Fluid DOT 4 (500ml)','BRK-FLD-DOT4-500','Castrol','Brakes',40,15,7,18,'Castrol (Malaysia) Sdn Bhd','Castrol React Performance DOT 4 brake fluid. High dry boiling point of 265 degrees C for consistent brake performance. Compatible with all DOT 3 and DOT 4 brake systems. Replace every 2 years.'),
('SP-009','Drive Chain & Sprocket Kit','TRN-CHAIN-DID-520','DID','Transmission',12,5,65,130,'Daido Kogyo (DID) Southeast Asia','DID 520 ERV7 X-Ring chain and JT steel sprocket kit. The X-Ring seal reduces friction for increased power transfer and chain longevity. Includes front sprocket, rear sprocket, and 120-link chain.'),
('SP-010','Clutch Cable','TRN-CLTC-VNH-001','Venhill','Transmission',14,6,14,35,'Venhill Engineering Ltd','Venhill stainless steel braided clutch cable with Teflon inner lining. Prevents cable expansion for a precise clutch feel. Pre-stretched for minimal bedding-in time. Includes adjusters at both ends.'),
('SP-011','Throttle Cable (Push/Pull Set)','TRN-THRC-UNI-001','Motion Pro','Transmission',4,5,18,42,'Motion Pro Inc.','Motion Pro stainless throttle cable push/pull set with a nylon-lined inner cable for smooth operation. Direct-fit replacement for OEM cables. Reduces throttle effort and eliminates sticky throttle symptoms.'),
('SP-012','Front Fork Oil Seal Set','SUS-SEAL-F-UNI-001','All Balls Racing','Suspension',15,6,18,42,'All Balls Racing Parts','All Balls Racing fork seal kit with PTFE-coated seals and dust wipers. Prevents fork oil leaks that cause poor suspension performance. Includes two seals and two dust wipers.'),
('SP-013','Rear Shock Absorber','SUS-SHCK-R-YSS-001','YSS','Suspension',2,3,120,260,'YSS Thailand Co., Ltd.','YSS G-Sport rear shock absorber with stepped rebound damping adjustment. Mono-tube gas pressure design provides superior heat dissipation. Improves handling and reduces bottoming-out. Direct bolt-on replacement.'),
('SP-014','Steering Head Bearing Kit','SUS-STRBR-ABS-001','All Balls Racing','Suspension',10,4,28,65,'All Balls Racing Parts','All Balls Racing steering head bearing and seal kit. Tapered roller bearings replace OEM ball bearings for improved steering precision. Eliminates head-shake and notchy steering.'),
('SP-015','Motorcycle Battery 12V 10Ah','ELC-BAT-YUA-12V','Yuasa','Electrical',10,4,42,90,'Yuasa Battery (Malaysia) Sdn Bhd','Yuasa YTZ12S AGM maintenance-free battery. Factory-activated and shipped ready to install. Vibration resistant construction and superior cranking power in all weather conditions.'),
('SP-016','LED Headlight Conversion Kit H4','ELC-LED-H4-PRJ-001','Koso','Electrical',2,4,55,130,'Koso Electronics Co., Ltd.','Koso H4 hi/lo LED headlight conversion kit with fan-cooled 6000K white LED chip. Produces 3600LM significantly brighter than stock halogen bulbs. Plug-and-play fitment with anti-flicker relay.'),
('SP-017','Universal LED Turn Signal Kit (4pcs)','ELC-TURN-LED-UNI','Rizoma','Electrical',12,5,40,95,'Rizoma Srl','Rizoma Corsa LED flush-mount turn signals with hyper-flash resistors included. CNC-machined aluminium body with smoked diffuser lens. M8 threaded stem fits most OEM mirror mounts.'),
('SP-018','Fuel Pump Assembly','FUL-PUMP-IND-001','Indian Genuine Parts','Fuel System',1,3,180,380,'Indian Motorcycle APAC Pte Ltd','Genuine Indian Motorcycle fuel pump module assembly. Direct OEM replacement for Scout and Chief models. Includes pump, sending unit, and integrated fuel filter. Restores fuel pressure and eliminates hard-start issues.'),
('SP-019','Carburetor Main Jet Kit','FUL-JET-DYN-RE001','Dynojet','Fuel System',20,8,22,55,'Dynojet Research Inc.','Dynojet main jet kit for carburetted motorcycles. Includes a range of jet sizes (100-130) for altitude and performance tuning. Brass construction with precise tolerances for consistent fuel delivery.'),
('SP-020','Pilot Road 5 Front Tyre 120/70 ZR17','TYR-PR5-F-120','Michelin','Tyres & Wheels',10,4,95,195,'Michelin Tyre PLC Malaysia','Michelin Pilot Road 5 front tyre in 120/70 ZR17. 2CT+ compound technology and XST+ sipes for maximum wet grip while maintaining dry performance and longevity.'),
('SP-021','Pilot Road 5 Rear Tyre 180/55 ZR17','TYR-PR5-R-180','Michelin','Tyres & Wheels',10,4,120,235,'Michelin Tyre PLC Malaysia','Michelin Pilot Road 5 rear tyre in 180/55 ZR17. 2CT+ dual compound construction - harder centre for mileage, softer shoulders for cornering grip. Ideal for sport-touring riders.'),
('SP-022','Wheel Bearing Kit (Front + Rear)','TYR-WHLBR-ABS-001','All Balls Racing','Tyres & Wheels',3,4,32,72,'All Balls Racing Parts','All Balls Racing front and rear wheel bearing kit. Chrome steel bearings with C3 clearance rating and high-temperature grease seals. Eliminates wheel wobble. Includes all bearings and seals for complete replacement.'),
('SP-023','Slip-On Exhaust Silencer','EXH-SLP-AKR-001','Akrapovic','Exhaust',6,2,280,580,'Akrapovic d.o.o.','Akrapovic Racing Line titanium slip-on exhaust silencer. Reduces weight by up to 1.8kg, increases power by 3-5hp, and delivers the unmistakable Akrapovic sound. E-mark approved for road use.'),
('SP-024','Royal Enfield Touring Silencer','EXH-TOUR-RE-001','RE Accessories','Exhaust',5,3,85,180,'Royal Enfield Motors (M) Sdn Bhd','Genuine Royal Enfield stainless steel touring silencer. Deep, throaty exhaust note without excessive drone. Brushed stainless finish. Comes with all mounting hardware. E-mark certified and warranty-friendly.'),
('SP-025','Fairing Clip & Bolt Kit','BDY-FAIR-CLIP-HON','Honda Genuine Parts','Body & Frame',22,8,12,28,'Honda Motor Distributors Sdn Bhd','Genuine Honda OEM fairing bolt and push-clip kit. Replaces missing or stripped fasteners that cause fairing panels to rattle or misalign. Includes all clips, push-rivets, and M5/M6 bolts.'),
('SP-026','Tail Light LED Assembly','BDY-TAIL-LED-KAW','Kawasaki Genuine Parts','Body & Frame',3,4,45,98,'Kawasaki Motors (M) Sdn Bhd','Genuine Kawasaki LED tail light and brake light assembly. Direct plug-and-play OEM replacement. Brighter than halogen with lower power draw. Includes integrated licence plate light.');
INSERT INTO accessories (id, name, article_number, brand, category, size, stock, reorder_qty, cost, selling_price, vendor, description) VALUES
